export const useCountriesSchemaField = (
  options?: Omit<FlowOptions, 'jsonSchemaVersion'> & {
    queryOptions?: { enabled?: boolean };
  },
) => {
  const { client } = useClient();
  const { data: countries, isLoading } = useQuery({
    ...countriesOptions(client as Client, 'contractor-onboarding-countries'),
    select: (response) => {
      return (
        response.data?.data?.map((country) => {
          return {
            label: country.name,
            value: country.code,
            eor_onboarding: country.eor_onboarding,
            contractor_products_available:
              country.contractor_products_available,
          };
        }) || []
      );
    },
    enabled: options?.queryOptions?.enabled,
  });

  const selectCountryForm = createHeadlessForm(
    selectCountryStepSchema.data.schema,
    {},
    options,
  );

  if (countries) {
    const countryField = selectCountryForm.fields.find(
      (field) => field.name === 'country',
    );
    if (countryField) {
      countryField.options = countries;
    }
  }

  return {
    isLoading,
    selectCountryForm,
    countries,
  };
};

/**
 * Get contractor onboarding details schema with currency options overridden
 * from the getIndexContractorCurrency endpoint
 */
export const useContractorOnboardingDetailsSchemaWithCurrencies = ({
  countryCode,
  employmentId,
  fieldValues,
  options,
}: {
  countryCode: string;
  fieldValues: FieldValues;
  employmentId: string;
  options?: FlowOptions & { queryOptions?: { enabled?: boolean } };
}) => {
  const schemaQuery = useContractorOnboardingDetailsSchema({
    countryCode,
    employmentId,
    fieldValues,
    options,
  });

  const { data: currencies, isLoading: isLoadingCurrencies } =
    useContractorCurrencies({
      employmentId,
      options: {
        queryOptions: { enabled: options?.queryOptions?.enabled },
      },
    });

  const dataWithCurrencies = useMemo(() => {
    if (!schemaQuery.data || !currencies) {
      return schemaQuery.data;
    }

    const form = {
      ...schemaQuery.data,
      fields: schemaQuery.data.fields.map((field) => {
        if (field.name !== 'payment_terms') {
          return field;
        }

        return {
          ...field,
          fields: (field.fields as $TSFixMe[])?.map((nestedField: $TSFixMe) => {
            if (nestedField.name !== 'compensation_currency_code') {
              return nestedField;
            }

            // Return a new object with overridden options
            return {
              ...nestedField,
              options: currencies.map((currency) => ({
                label: currency.code,
                value: currency.code,
                meta: { source: currency.source },
              })),
            };
          }),
        };
      }),
    };

    return form;
  }, [schemaQuery.data, currencies]);

  return {
    ...schemaQuery,
    data: dataWithCurrencies as $TSFixMe,
    isLoading: schemaQuery.isLoading || isLoadingCurrencies,
  };
};
